#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+10;
int n,h[maxn],x,ans[maxn],mx[maxn];
deque<int> a; 
int main(){
    cin>>n>>x;
    for(int i=1;i<=n;i++){
    	cin>>h[i];
    	while(!a.empty() && h[a.back()]>h[i])a.pop_back();
    	a.push_back(i);
    	if(i>=x){
    		while(!a.empty() && a.front()<=i-x)a.pop_front();
    		ans[i-x+1]=h[a.front()];
		}
	}
	while(!a.empty())a.pop_back();
	for(int i=1;i<=n;i++){
    	while(!a.empty() && ans[a.back()]<ans[i])a.pop_back();
    	a.push_back(i);
		while(!a.empty() && a.front()<=i-x)a.pop_front();
    	mx[i]=ans[a.front()];
	}
	//for(int i=1;i<=n;i++)cout<<mx[i]<<' ';
	//cout<<endl;
    //for(int i=1;i<=n-x+1;i++)cout<<ans[i]<<' ';
    //cout<<endl;
	long long sum=0;
    for(int i=1;i<=n;i++){
    	sum+=h[i]-mx[i];
	}
	cout<<sum<<endl;
	
	int gd=0,kd=0;
	int cs=0;
	for(int i=1;i<=n;i++){
		if(mx[i]!=gd){
			cs++;
			kd=i+x-1;
		}
		if(i>kd){
			cs++;
			kd=i+x-1;
		}
		gd=mx[i];
	}
	cout<<cs;
    return 0;
}
